const raw = $input.item.json;
const aiText = raw.output[0].content[0].text;
const aiData = JSON.parse(aiText.replace(/```json|```/g, '').trim());

const incidencia = $('Loop Followup').first().json;

return {
  shipping_code: incidencia['NUMERO DE ENVIO'],
  numero_pedido: incidencia['NUMERO DE PEDIDO'],
  tienda: incidencia['TIENDA'],
  credencial: incidencia['CREDENCIAL'],
  incidencia_registrada: incidencia['INCIDENCIA'],
  sigue_incidencia: aiData.sigue_incidencia === true,
  estado_actual: aiData.estado_actual || '',
  justification: aiData.justification || '',
  email_body: aiData.email_body || ''
};

return [
  { json: { client: 'HAMINOS', credencial: 'HAMINOS', centers: ['4863000001'], access_token: $('Token HAMINOS FW').first().json.access_token } },
  { json: { client: 'MIESTERY', credencial: 'MIESTERY', centers: ['4768500003'], access_token: $('Token MIESTERY FW').first().json.access_token } },
  { json: { client: 'KULTUDENDA', credencial: 'KULTUDENDA', centers: ['4541600001', '4541600002'], access_token: $('Token KULTUDENDA FW').first().json.access_token } },
  { json: { client: 'SNAPPY', credencial: 'SNAPPY', centers: ['4735200001', '4735200002', '4735200003', '4735200004', '4735200005'], access_token: $('Token SNAPPY FW').first().json.access_token } }
];

const ayer = $now.minus({days: 1}).toFormat('yyyy-MM-dd');
const credencial = $('Loop Clientes 0000').item.json.credencial;
const client = $('Loop Clientes 0000').item.json.client;

const result = [];
for (const item of $input.all()) {
  const code = String(item.json.shipping_status_code || '');
  const rawDate = String(item.json.shipping_status_datetime || '');
  let fecha = '';
  if (rawDate) {
    try {
      const d = new Date(rawDate);
      d.setHours(d.getHours() + 1);
      fecha = d.toISOString().substring(0, 10);
    } catch(e) {
      fecha = rawDate.substring(0, 10);
    }
  }
  if ((code === '0000' || code === '0030') && fecha === ayer) {
    result.push({ json: { ...item.json, credencial, client, fecha_estado_local: fecha } });
  }
}
return result;

const pedido = $input.item.json;
const shippingCode = pedido.shipping_code;
const numeroPedido = (pedido.client_references && pedido.client_references[0]) || '';
const centerCode = String(pedido.client_center_code || '');
const credencial = pedido.credencial;

const emailMap = {
  'HAMINOS': 'incidenciashaminos@gmail.com',
  'MIESTERY': 'incidenciasamzdiscounts01@gmail.com',
  'KULTUDENDA': 'incidenciaskulturdenda@gmail.com',
  'SNAPPY': 'incidenciassnappyblue@gmail.com'
};
const destinatario = emailMap[credencial] || '';

return [{
  json: {
    shipping_code: shippingCode,
    numero_pedido: numeroPedido,
    tienda: credencial,
    centro: centerCode,
    credencial,
    fecha_estado: pedido.fecha_estado_local || '',
    destinatario,
    email_subject: `ALERTA INTERNA: Envio ${shippingCode} grabado sin recoger`,
    email_body: `El envio ${shippingCode} figura como grabado o recogida sin programar desde ayer. Revisar con almacen.`
  }
}];
